import JsSIP from 'jssip';
import { CONFIG } from './config.js';

// Thin wrapper around a JsSIP UA configured for non-registering, audio-only
// outbound calling over a SIP-WebRTC gateway.
export class Phone {
	constructor(handlers = {}) {
	    this.ua = null;
	    this.session = null;
	    this.remoteStream = null;
        this.handlers = {
            onStatus:       () => {},   // (text, level)
            onLog:          () => {},   // (msg)
            onRemoteStream: () => {},   // (MediaStream)
            onSession:      () => {},   // ({direction, target})
            onProgress:     () => {},
            onAccepted:     () => {},
            onEnded:        () => {},   // (cause)
            onFailed:       () => {},   // (cause)
            ...handlers,
        };
    }

    start() {
        const socket = new JsSIP.WebSocketInterface(CONFIG.wsServer);
        this.ua = new JsSIP.UA({
            sockets:        [socket],
            uri:            CONFIG.sipUri,
            display_name:   CONFIG.displayName,
            register:       false,
            session_timers: false,
        });

        this.ua.on('connecting',   () => { this.handlers.onStatus('connecting',   'warn'); this.handlers.onLog('ws connecting'); });
        this.ua.on('connected',    () => { this.handlers.onStatus('connected',    'ok');   this.handlers.onLog('ws connected'); });
        this.ua.on('disconnected', () => { this.handlers.onStatus('disconnected', 'bad');  this.handlers.onLog('ws disconnected'); });

        this.ua.on('newRTCSession', (e) => {
            if (e.originator === 'remote') {
                this.handlers.onLog('unexpected incoming call rejected');
                e.session.terminate();
                return;
            }
            this._wire(e.session);
        });

        this.ua.start();
    }

    isReady() {
        return this.ua?.isConnected() === true;
    }

    hasActiveSession() {
        return this.session !== null;
    }

    call(input) {
        if (!this.isReady())       throw new Error('ws not connected');
        if (this.hasActiveSession()) throw new Error('session already active');

        const target = this._buildTarget(input);
        if (!target) throw new Error('empty destination');

        this.handlers.onLog(`calling ${target}`);
        this.handlers.onSession({ direction: 'Outgoing', target: input.trim() });

        this.ua.call(target, {
            mediaConstraints: { audio: true, video: false },
            rtcOfferConstraints: {
                offerToReceiveAudio: true,
                offerToReceiveVideo: false,
            },
            pcConfig: {
                iceServers:    CONFIG.iceServers,
                bundlePolicy:  'max-bundle',
                rtcpMuxPolicy: 'require',
            },
        });
    }

    hangup() {
        if (!this.session) return;
        this.handlers.onLog('hangup');
        try { this.session.terminate(); }
        catch (e) { this.handlers.onLog('terminate error: ' + e.message); }
    }

	_wire(session) {
	    this.session = session;
	    this.remoteStream = null;

	    session.on('peerconnection', (e) => {
	        const pc = e.peerconnection;
	        this.handlers.onLog('peerconnection created');
	        this._logPeerConnectionMediaState(pc, 'peerconnection created');

	        pc.addEventListener('track', (ev) => {
	            const stream = ev.streams[0] || new MediaStream([ev.track]);
	            this.handlers.onLog(
	                `remote ${ev.track.kind} track received: state=${ev.track.readyState}, muted=${ev.track.muted}`
	            );
	            this._logPeerConnectionMediaState(pc, 'track event');
	            this._setRemoteStream(stream);
	        });
	    });

	    session.on('progress',  ()   => { this.handlers.onLog('progress');  this.handlers.onProgress(); });
	    session.on('accepted',  ()   => { this.handlers.onLog('accepted');  this._logPeerConnectionMediaState(session.connection, 'accepted'); this._collectRemoteStream(session.connection); this.handlers.onAccepted(); });
	    session.on('confirmed', ()   => { this.handlers.onLog('confirmed'); this._logPeerConnectionMediaState(session.connection, 'confirmed'); this._collectRemoteStream(session.connection); });
	    session.on('ended',     (e)  => { this.handlers.onLog('ended: '  + (e.cause || 'normal'));  this.session = null; this.remoteStream = null; this.handlers.onEnded(e.cause); });
	    session.on('failed',    (e)  => { this.handlers.onLog('failed: ' + (e.cause || 'unknown')); this.session = null; this.remoteStream = null; this.handlers.onFailed(e.cause); });
	}

	_setRemoteStream(stream) {
	    if (!stream || this.remoteStream === stream) return;
	    const audioTracks = stream.getAudioTracks();
	    this.handlers.onLog(`remote stream ready: audioTracks=${audioTracks.length}`);
	    this.remoteStream = stream;
	    this.handlers.onRemoteStream(stream);
	}

	_collectRemoteStream(pc) {
	    if (!pc || this.remoteStream) return;
	    // Do not rely only on the browser "track" event. With SIP/WebRTC flows
	    // using offerToReceiveAudio, the audio receiver can already exist before
	    // Chrome emits a useful track event, or the event can be missed by library
	    // timing. getReceivers() is the current peer-connection state and lets us
	    // attach remote audio deterministically after accepted/confirmed.
	    const tracks = pc.getReceivers()
	        .map(receiver => receiver.track)
	        .filter(track => track && track.kind === 'audio');
	    if (tracks.length === 0) {
	        this.handlers.onLog('remote stream check: no receiver audio tracks');
	        return;
	    }
	    this.handlers.onLog(`remote stream recovered from receivers: audioTracks=${tracks.length}`);
	    this._setRemoteStream(new MediaStream(tracks));
	}

	_logPeerConnectionMediaState(pc, label) {
	    if (!pc) {
	        this.handlers.onLog(`${label}: no peerconnection`);
	        return;
	    }

	    const receivers = pc.getReceivers ? pc.getReceivers() : [];
	    const transceivers = pc.getTransceivers ? pc.getTransceivers() : [];
	    const receiverSummary = receivers
	        .map((receiver, i) => {
	            const track = receiver.track;
	            return `${i}:${track?.kind || 'none'}:${track?.readyState || 'none'}:${track?.muted ? 'muted' : 'unmuted'}`;
	        })
	        .join(',');
	    const transceiverSummary = transceivers
	        .map((transceiver, i) => {
	            const receiverTrack = transceiver.receiver?.track;
	            return `${i}:${transceiver.mid ?? 'no-mid'}:${transceiver.direction}/${transceiver.currentDirection || 'none'}:${receiverTrack?.kind || 'none'}:${receiverTrack?.readyState || 'none'}`;
	        })
	        .join(',');

	    this.handlers.onLog(
	        `${label}: signaling=${pc.signalingState}, receivers=[${receiverSummary}], transceivers=[${transceiverSummary}]`
	    );
	}

    _buildTarget(input) {
        const v = (input ?? '').trim();
        if (!v) return null;
        if (v.startsWith('sip:') || v.startsWith('sips:')) return v;
        return `sip:${v}@${CONFIG.outboundDomain}`;
    }
}
