import JsSIP from 'jssip';
import { Phone } from './phone.js';

const DEBUG_NS = 'JsSIP:*';
const DEBUG_KEY = 'jssipDebugEnabled';

function setJsSIPDebug(enabled) {
    if (enabled) {
        JsSIP.debug.enable(DEBUG_NS);
        localStorage.setItem(DEBUG_KEY, '1');
    } else {
        JsSIP.debug.disable();
        localStorage.removeItem(DEBUG_KEY);
    }
}

const els = {
    statusDot:     document.getElementById('statusDot'),
    statusText:    document.getElementById('statusText'),
    number:        document.getElementById('number'),
    callBtn:       document.getElementById('callBtn'),
    hangupBtn:     document.getElementById('hangupBtn'),
    callPanel:     document.getElementById('callPanel'),
    callDirection: document.getElementById('callDirection'),
    callNumber:    document.getElementById('callNumber'),
    callState:     document.getElementById('callState'),
    callTimer:     document.getElementById('callTimer'),
    log:           document.getElementById('logOutput'),
    remoteAudio:   document.getElementById('remoteAudio'),
    debugToggle:   document.getElementById('debugToggle'),
    speakerBtn:    document.getElementById('speakerBtn'),
    vuBar:         document.getElementById('vuBar'),
};

let audioCtx = null;
let vuRaf = null;
let vuPeakLogged = false;

function startVU(stream) {
    stopVU();
    try {
        audioCtx = audioCtx || new (window.AudioContext || window.webkitAudioContext)();
        if (audioCtx.state === 'suspended') audioCtx.resume();
        const src = audioCtx.createMediaStreamSource(stream);
        const analyser = audioCtx.createAnalyser();
        analyser.fftSize = 512;
        src.connect(analyser);
        const buf = new Uint8Array(analyser.fftSize);
        vuPeakLogged = false;
        const tick = () => {
            analyser.getByteTimeDomainData(buf);
            let peak = 0;
            for (let i = 0; i < buf.length; i++) {
                const v = Math.abs(buf[i] - 128);
                if (v > peak) peak = v;
            }
            const pct = Math.min(100, (peak / 128) * 100 * 1.5);
            els.vuBar.style.width = pct.toFixed(0) + '%';
            if (!vuPeakLogged && peak > 4) {
                log('remote audio detected (peak ' + peak + ')');
                vuPeakLogged = true;
            }
            vuRaf = requestAnimationFrame(tick);
        };
        tick();
    } catch (e) {
        log('VU init failed: ' + e.message);
    }
}

function stopVU() {
    if (vuRaf) cancelAnimationFrame(vuRaf);
    vuRaf = null;
    if (els.vuBar) els.vuBar.style.width = '0%';
}

const debugInit = localStorage.getItem(DEBUG_KEY) === '1';
els.debugToggle.checked = debugInit;
setJsSIPDebug(debugInit);
els.debugToggle.addEventListener('change', (e) => setJsSIPDebug(e.target.checked));

let callStartedAt = 0;
let timerHandle = null;

function log(msg) {
    const t = new Date().toLocaleTimeString();
    els.log.textContent = `[${t}] ${msg}\n` + els.log.textContent;
    console.log('[webphone]', msg);
}

function setStatus(text, level) {
    els.statusText.textContent = text;
    els.statusDot.className = 'dot' + (level ? ' ' + level : '');
}

function showCallPanel(direction, number) {
    els.callDirection.textContent = direction;
    els.callNumber.textContent = number;
    els.callState.textContent = 'connecting…';
    els.callTimer.textContent = '00:00';
    els.callPanel.classList.remove('hidden');
}

function hideCallPanel() {
    els.callPanel.classList.add('hidden');
    stopTimer();
}

function startTimer() {
    callStartedAt = Date.now();
    timerHandle = setInterval(() => {
        const s = Math.floor((Date.now() - callStartedAt) / 1000);
        const mm = String(Math.floor(s / 60)).padStart(2, '0');
        const ss = String(s % 60).padStart(2, '0');
        els.callTimer.textContent = `${mm}:${ss}`;
    }, 500);
}

function stopTimer() {
    if (timerHandle) { clearInterval(timerHandle); timerHandle = null; }
}

async function changeSpeaker() {
    const audio = document.getElementById('remoteAudio');
    try {
        if (navigator.mediaDevices.selectAudioOutput) {
            const d = await navigator.mediaDevices.selectAudioOutput();
            await audio.setSinkId(d.deviceId);
            log(`speaker: ${d.label}`);
            return;
        }
        if (typeof audio.setSinkId === 'function') {
            await navigator.mediaDevices.getUserMedia({ audio: true });
            const devs = (await navigator.mediaDevices.enumerateDevices())
                .filter(d => d.kind === 'audiooutput');
            if (devs.length === 0) { log('no audiooutput devices'); return; }
            const list = devs.map((d, i) => `${i}: ${d.label || d.deviceId}`).join('\n');
            const choice = prompt('Pick speaker:\n' + list);
            if (choice === null) return;
            const d = devs[+choice];
            if (!d) { log('invalid speaker index'); return; }
            await audio.setSinkId(d.deviceId);
            log(`speaker: ${d.label}`);
            return;
        }
        alert('Speaker selection not supported in this browser');
    } catch (err) {
        log('speaker change failed: ' + err.message);
    }
}

const phone = new Phone({
    onStatus: (text, level) => {
        setStatus(text, level);
        els.callBtn.disabled = level !== 'ok';
	    },
	    onLog: log,
	    onRemoteStream: (stream) => {
	        const audio = els.remoteAudio;
	        audio.srcObject = stream;
	        audio.muted = false;
	        audio.volume = 1;
	        audio.autoplay = true;

	        const tracks = stream.getAudioTracks();
	        log(`remote stream attached: audioTracks=${tracks.length}`);
	        for (const track of tracks) {
	            log(`remote track: id=${track.id}, state=${track.readyState}, muted=${track.muted}, enabled=${track.enabled}`);
	            track.addEventListener('mute', () => log(`remote track muted: id=${track.id}`));
	            track.addEventListener('unmute', () => log(`remote track unmuted: id=${track.id}`));
	            track.addEventListener('ended', () => log(`remote track ended: id=${track.id}`));
	        }

	        const playResult = audio.play();
	        if (playResult?.catch) {
	            playResult
	                .then(() => log('remote audio playback started'))
	                .catch(e => log('remote audio playback failed: ' + e.message));
	        }

	        startVU(stream);
	    },
    onSession: ({ direction, target }) => {
        els.callBtn.disabled = true;
        showCallPanel(direction, target);
    },
    onProgress: () => { els.callState.textContent = 'ringing…'; },
    onAccepted: () => { els.callState.textContent = 'in call';  startTimer(); },
    onEnded:    () => { stopVU(); hideCallPanel(); els.callBtn.disabled = !phone.isReady(); els.number.focus(); },
    onFailed:   () => { stopVU(); hideCallPanel(); els.callBtn.disabled = !phone.isReady(); els.number.focus(); },
});

els.callBtn.addEventListener('click', () => {
    try { phone.call(els.number.value); }
    catch (e) { log(e.message); }
});
els.hangupBtn.addEventListener('click', () => phone.hangup());
els.speakerBtn.addEventListener('click', changeSpeaker);
els.number.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') els.callBtn.click();
});

phone.start();
